#include <stdio.h>
#include <stdlib.h>

#define MOD 222

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        if (K > N * (N - 1) / 2) { // impossible
            printf("0\n");
            continue;
        }
        int *prev = (int*)calloc(K + 1, sizeof(int));
        int *cur  = (int*)calloc(K + 1, sizeof(int));
        prev[0] = 1; // dp[0][0]
        for (int i = 1; i <= N; ++i) {
            int maxInv = i * (i - 1) / 2;
            if (maxInv > K) maxInv = K;
            int window = 0;
            for (int j = 0; j <= maxInv; ++j) {
                window = (window + prev[j]) % MOD;
                if (j >= i) {
                    window = (window - prev[j - i] + MOD) % MOD;
                }
                cur[j] = window;
            }
            // swap rows
            int *tmp = prev; prev = cur; cur = tmp;
            // clear cur for next iteration (only up to next maxInv)
            for (int j = 0; j <= maxInv; ++j) cur[j] = 0;
        }
        printf("%d\n", prev[K] % MOD);
        free(prev);
        free(cur);
    }
    return 0;
}

