const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const K = input[idx++];
  if (K > N * (N - 1) / 2) { outputs.push('0'); continue; }
  let prev = new Array(K + 1).fill(0);
  let cur = new Array(K + 1).fill(0);
  prev[0] = 1;
  for (let i = 1; i <= N; i++) {
    let maxInv = i * (i - 1) / 2;
    if (maxInv > K) maxInv = K;
    let window = 0;
    for (let j = 0; j <= maxInv; j++) {
      window = (window + prev[j]) % MOD;
      if (j >= i) window = (window - prev[j - i] + MOD) % MOD;
      cur[j] = window;
